var numDecodings = function(s) {
    const n = s.length;
    let prev2 = 1, prev1 = s[0] !== '0' ? 1 : 0;
    for (let i = 1; i < n; i++) {
        let cur = 0;
        if (s[i] !== '0') cur += prev1;
        const two = parseInt(s.slice(i - 1, i + 1), 10);
        if (two >= 10 && two <= 26) cur += prev2;
        prev2 = prev1;
        prev1 = cur;
    }
    return prev1;
};
